class MigrationRunner
{
    // Breaking change (EF Core 9): Migrate() now manages its own transactions
    // and throws InvalidOperationException if called inside an execution strategy
    // or an explicit transaction.
    void ApplyMigrations(AppDbContext db)
    {
        db.Database.Migrate();
    }
}

