using Microsoft.EntityFrameworkCore;

// Cosmos DB project context — demonstrates EF Core 9 breaking change fixes.
class CosmosDbContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void OnConfiguring(DbContextOptionsBuilder options)
    {
        options.UseCosmos(
            "AccountEndpoint=https://localhost:8081/;AccountKey=placeholder",
            "CatalogDb");

        // Breaking change #1 (Cosmos): Synchronous I/O now throws by default.
        // Fix: either convert all queries to async (preferred) or opt-in:
        options.ConfigureWarnings(w =>
            w.Ignore(Microsoft.EntityFrameworkCore.Diagnostics.CosmosEventId.SyncNotSupported));
    }

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(b =>
        {
            b.ToContainer("Products");
            b.HasPartitionKey(p => p.Category);

            // Breaking change #2 (Cosmos): EF Core 9 changed the default
            // discriminator property from "Discriminator" to "$type".
            // Existing documents already store "Discriminator", so we must
            // explicitly keep the old property name to avoid data mismatch.
            b.HasDiscriminator<string>("Discriminator");
        });
    }
}

class Product
{
    public string Id { get; set; } = null!;
    public string Name { get; set; } = null!;
    public string Category { get; set; } = null!;
}

